class ApiClient {
  static const String baseUrl = 'https://api.example.com';
  String? _authToken;
  final http.Client _client = http.Client();

  Future<Map<String, dynamic>> login(String username, String password) async {
    try {
      final response = await _client.post(
        Uri.parse('$baseUrl/auth/login'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode({
          'username': username,
          'password': password,
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        _authToken = data['token'];
        return {'success': true, 'data': data};
      } else {
        return {
          'success': false,
          'error': 'Login failed: ${response.statusCode}'
        };
      }
    } catch (e) {
      return {'success': false, 'error': 'Network error: $e'};
    }
  }

  Future<Map<String, dynamic>> getUserProfile() async {
    if (_authToken == null) {
      return {'success': false, 'error': 'Not authenticated'};
    }

    try {
      final response = await _client.get(
        Uri.parse('$baseUrl/user/profile'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_authToken',
        },
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return {'success': true, 'data': data};
      } else if (response.statusCode == 401) {
        _authToken = null;
        return {'success': false, 'error': 'Authentication expired'};
      } else {
        return {
          'success': false,
          'error': 'Failed to fetch profile: ${response.statusCode}'
        };
      }
    } catch (e) {
      return {'success': false, 'error': 'Network error: $e'};
    }
  }

  Future<Map<String, dynamic>> updateProfile(
      Map<String, dynamic> profileData) async {
    if (_authToken == null) {
      return {'success': false, 'error': 'Not authenticated'};
    }

    try {
      final response = await _client.put(
        Uri.parse('$baseUrl/user/profile'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_authToken',
        },
        body: jsonEncode(profileData),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return {'success': true, 'data': data};
      } else {
        return {
          'success': false,
          'error': 'Update failed: ${response.statusCode}'
        };
      }
    } catch (e) {
      return {'success': false, 'error': 'Network error: $e'};
    }
  }

  Future<Map<String, dynamic>> syncData(List<Map<String, dynamic>> localData) async {
    if (_authToken == null) {
      return {'success': false, 'error': 'Not authenticated'};
    }

    try {
      final response = await _client.post(
        Uri.parse('$baseUrl/sync'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_authToken',
        },
        body: jsonEncode({'data': localData}),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return {'success': true, 'data': data};
      } else {
        return {
          'success': false,
          'error': 'Sync failed: ${response.statusCode}'
        };
      }
    } catch (e) {
      return {'success': false, 'error': 'Network error: $e'};
    }
  }

  Future<Map<String, dynamic>> fetchData(String endpoint) async {
    if (_authToken == null) {
      return {'success': false, 'error': 'Not authenticated'};
    }

    try {
      final response = await _client.get(
        Uri.parse('$baseUrl/$endpoint'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_authToken',
        },
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return {'success': true, 'data': data};
      } else {
        return {
          'success': false,
          'error': 'Fetch failed: ${response.statusCode}'
        };
      }
    } catch (e) {
      return {'success': false, 'error': 'Network error: $e'};
    }
  }

  void logout() {
    _authToken = null;
  }

  bool get isAuthenticated => _authToken != null;

  void dispose() {
    _client.close();
  }
}

